from flask import Flask, request, jsonify
from prometheus_client import start_http_server, Summary, Counter, Histogram
import re
import os

app = Flask(__name__)

# Prometheus metrics
REQUEST_COUNT = Counter('api_requests_total', 'Total API Requests', ['user_id', 'api_key'])
REQUEST_LATENCY = Histogram('api_request_latency_seconds', 'Request latency', ['user_id', 'api_key'])
REQUEST_BODY_SIZE = Summary('api_request_body_size_bytes', 'Request body size', ['user_id', 'api_key'])

# Input validation regex
USER_ID_REGEX = re.compile(r'^[a-zA-Z0-9_-]{1,30}$')
API_KEY_REGEX = re.compile(r'^[a-zA-Z0-9_-]{1,40}$')

def validate_input(user_id, api_key):
    if not USER_ID_REGEX.match(user_id) or not API_KEY_REGEX.match(api_key):
        raise ValueError("Invalid user ID or API key")

@app.route('/api', methods=['POST'])
def api_endpoint():
    user_id = request.headers.get('X-User-ID')
    api_key = request.headers.get('X-API-Key')
    
    try:
        validate_input(user_id, api_key)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    request_body = request.get_json()
    body_size = len(request.data)

    with REQUEST_LATENCY.labels(user_id=user_id, api_key=api_key).time():
        REQUEST_COUNT.labels(user_id=user_id, api_key=api_key).inc()
        REQUEST_BODY_SIZE.labels(user_id=user_id, api_key=api_key).observe(body_size)

    return jsonify({"message": "Request processed"}), 200

